//! Hope Jar Kaiju — the |Co₀|-key entropy battery (the "faster monster").
//!
//! The apex inflation rung above the Leech tier.  Capacity is the order of the
//! Conway group Co₀ = Aut(Leech lattice):
//!
//!   Capacity = |Co₀| = 8,315,553,613,086,720,000
//!            = 24 × 196560 × 1,762,725,888,000
//!            = (Leech dim) × (Leech kissing number) × (carriers per slot).
//!
//! 196560 LANES — the Leech minimal vectors / kissing number, 819× the E₈ jar's
//! 240 — so the discharge field has far more parallel point-query lanes.  Like
//! every hope jar this is LATENT: ~170 seeds are stored and keys are *inflated*
//! deterministically at discharge — never materialised (the full field is
//! ~6.6×10¹⁹ bytes).  HONEST: `predict()` is O(1) regardless of capacity; a
//! larger jar buys key-space COVERAGE (fewer collisions), not faster per-query.
//!
//! Lean SSOT: `Gnosis.HopeJarKaiju.kaiju_jar_capacity_eq_co0` (24·196560·… = |Co₀|),
//! resting on `Gnosis.ConwayLeechOrders` (|Co₀|) and the kissing number 196560.

use crate::hope_jar::BoxState;

/// |Co₀| — the full kaiju tier capacity. Latent, never materialised.
pub const KAIJU_TIER_CAPACITY: u64 = 8_315_553_613_086_720_000;
/// Leech lattice dimension — the phase count.
pub const LEECH_PHASES: usize = 24;
/// Leech kissing number / minimal vectors — the lane count (819 × E₈).
pub const KISSING_LANES: usize = 196_560;
/// Carriers per (phase, lane) slot = |Co₀| / (24 · 196560).
pub const CARRIERS_PER_SLOT: u64 = 1_762_725_888_000;
/// Seeds needed to seal the jar.
pub const CHARGE_SEEDS: usize = 170;
/// Conway three-orbit decomposition of the 196560 minimal vectors.
pub const ORBIT_2: usize = 1_104;
pub const ORBIT_3: usize = 97_152;
pub const ORBIT_4: usize = 98_304;

const FIBONACCI_HASH: u64 = 11_400_714_819_323_198_485;
/// `discharge()` convenience cap — the latent slot is 1.7×10¹² carriers; never
/// materialise more than this many (the real API is the O(1) `predict`).
const DISCHARGE_CAP: usize = 96_768;

/// The Kaiju Hope Jar: sealed latent |Co₀|-key entropy battery.
#[derive(Clone, Debug)]
pub struct HopeJarKaiju {
    seeds: Vec<u64>,
    state: BoxState,
    charge_cost_us: u64,
    total_discharges: u64,
}

/// Lane code for one of the 196560 minimal-vector lanes, tagged by which Conway
/// orbit (norm-4 / norm-6 / norm-8 shell) it lives in.
fn lane_code(lane: usize) -> u64 {
    let orbit: u64 = if lane < ORBIT_2 {
        2
    } else if lane < ORBIT_2 + ORBIT_3 {
        3
    } else {
        4
    };
    orbit
        .wrapping_mul(FIBONACCI_HASH)
        .wrapping_add(0xdead_beef)
        .wrapping_add((lane as u64).wrapping_mul(FIBONACCI_HASH))
}

// ── THE KAIJU AS RUNTIME: three Conway orbits → three FOIL channels ──────────
//
// The Leech kissing number splits into three Conway orbits (1104 + 97152 + 98304
// = the norm-4/6/8 minimal-vector shells, `kaiju_jar_capacity_eq_co0`).  Those
// three shells map one-to-one onto the three sovereign operations — the same
// three-fold (ω³=1, `Gnosis.ThreeFoldSymmetry`) realised as a runtime scheduler:
//
//   norm-4 shell (1104,  tightest/rarest)   → Fork  (the selective split)
//   norm-6 shell (97152, the broad middle)  → Race  (the parallel exploration)
//   norm-8 shell (98304, the outer/largest) → Fold  (the convergence)
//
// So the kaiju jar IS the runtime: a cache key predicts into a lane, the lane's
// Conway orbit picks its fork/race/fold channel — O(1), latent, no extra state.

/// The three FOIL channels, one per Conway orbit of the kaiju lattice.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Channel {
    Fork,
    Race,
    Fold,
}

/// Route a lane to its FOIL channel by Conway orbit (norm-4 → Fork, norm-6 → Race,
/// norm-8 → Fold).
pub fn channel_of_lane(lane: usize) -> Channel {
    if lane < ORBIT_2 {
        Channel::Fork
    } else if lane < ORBIT_2 + ORBIT_3 {
        Channel::Race
    } else {
        Channel::Fold
    }
}

/// Route any shape hash to one of the three fork/race/fold channels via the lane
/// it predicts into — the kaiju jar's Conway-orbit structure used as the runtime's
/// three-channel scheduler.
pub fn kaiju_channel(shape_hash: u64) -> Channel {
    let lane = ((shape_hash / LEECH_PHASES as u64) % KISSING_LANES as u64) as usize;
    channel_of_lane(lane)
}

impl HopeJarKaiju {
    pub fn new() -> Self {
        Self { seeds: Vec::new(), state: BoxState::Empty, charge_cost_us: 0, total_discharges: 0 }
    }

    pub fn state(&self) -> BoxState {
        self.state
    }
    pub fn seeds_loaded(&self) -> usize {
        self.seeds.len()
    }
    pub fn total_discharges(&self) -> u64 {
        self.total_discharges
    }
    pub fn is_sealed(&self) -> bool {
        self.state == BoxState::Sealed
    }
    /// Full key capacity (latent) = |Co₀|.
    pub fn capacity(&self) -> u64 {
        KAIJU_TIER_CAPACITY
    }

    /// Charge from standing-wave (rain) seeds; seals at CHARGE_SEEDS.
    pub fn charge_from_seeds(&mut self, seeds: &[u64], analysis_time_us: u64) {
        if self.state == BoxState::Sealed {
            return;
        }
        self.state = BoxState::Charging;
        self.charge_cost_us += analysis_time_us;
        for &seed in seeds {
            if self.seeds.len() >= CHARGE_SEEDS {
                break;
            }
            self.seeds.push(seed);
        }
        if self.seeds.len() >= CHARGE_SEEDS {
            self.state = BoxState::Sealed;
        }
    }

    /// Deterministic per-slot seed.
    fn slot_seed(&self, phase: usize, lane: usize) -> u64 {
        let base = if self.seeds.is_empty() {
            FIBONACCI_HASH
        } else {
            self.seeds[(phase * KISSING_LANES + lane) % self.seeds.len()]
        };
        base.wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(lane_code(lane))
            .wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(phase as u64)
    }

    /// O(1) point query — predict a single key for a shape hash.  Cost is
    /// independent of capacity; the bigger jar only widens the key space.
    pub fn predict(&self, shape_hash: u64) -> u64 {
        if self.state != BoxState::Sealed {
            return 0;
        }
        let phase = (shape_hash % LEECH_PHASES as u64) as usize;
        let lane = ((shape_hash / LEECH_PHASES as u64) % KISSING_LANES as u64) as usize;
        let k = (shape_hash / (LEECH_PHASES as u64 * KISSING_LANES as u64)) % CARRIERS_PER_SLOT;
        self.slot_seed(phase, lane)
            .wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(k)
            .wrapping_mul(FIBONACCI_HASH)
    }

    /// Lazy carrier stream for one slot (latent count is 1.7×10¹²; iterate, do
    /// not collect the whole thing).
    pub fn discharge_iter(&self, phase: u8, lane: u32) -> impl Iterator<Item = u64> + '_ {
        let sealed = self.state == BoxState::Sealed;
        let p = (phase as usize) % LEECH_PHASES;
        let l = (lane as usize) % KISSING_LANES;
        let base = if sealed { self.slot_seed(p, l) } else { 0 };
        let count: u64 = if sealed { CARRIERS_PER_SLOT } else { 0 };
        (0..count).map(move |k| {
            base.wrapping_mul(FIBONACCI_HASH).wrapping_add(k).wrapping_mul(FIBONACCI_HASH)
        })
    }

    /// Materialise a CAPPED window of one slot's carriers (never the full 1.7e12).
    pub fn discharge_capped(&mut self, phase: u8, lane: u32) -> Vec<u64> {
        if self.state != BoxState::Sealed {
            return Vec::new();
        }
        self.total_discharges += 1;
        self.discharge_iter(phase, lane).take(DISCHARGE_CAP).collect()
    }
}

impl Default for HopeJarKaiju {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn rain_seeds() -> Vec<u64> {
        (0..CHARGE_SEEDS as u64).map(|i| i.wrapping_mul(2654435761).wrapping_add(1)).collect()
    }

    #[test]
    fn test_kaiju_capacity_is_co0() {
        assert_eq!(
            LEECH_PHASES as u64 * KISSING_LANES as u64 * CARRIERS_PER_SLOT,
            KAIJU_TIER_CAPACITY
        );
    }

    #[test]
    fn test_kaiju_lanes_are_kissing_number() {
        assert_eq!(KISSING_LANES, ORBIT_2 + ORBIT_3 + ORBIT_4); // 196560 = 1104+97152+98304
    }

    #[test]
    fn test_kaiju_charge_seal_predict() {
        let mut jar = HopeJarKaiju::new();
        jar.charge_from_seeds(&rain_seeds(), 1000);
        assert!(jar.is_sealed());
        let a = jar.predict(123456789);
        let b = jar.predict(123456789);
        assert_eq!(a, b); // deterministic
        assert_ne!(a, 0);
    }

    #[test]
    fn test_three_channels_one_per_orbit() {
        // each Conway orbit maps to exactly one fork/race/fold channel
        assert_eq!(channel_of_lane(0), Channel::Fork); // norm-4 shell
        assert_eq!(channel_of_lane(ORBIT_2), Channel::Race); // norm-6 shell
        assert_eq!(channel_of_lane(ORBIT_2 + ORBIT_3), Channel::Fold); // norm-8 shell
        assert_eq!(channel_of_lane(KISSING_LANES - 1), Channel::Fold); // last lane
        // routing a shape hash is deterministic and lands in one channel
        assert_eq!(kaiju_channel(123456789), kaiju_channel(123456789));
    }
}
